namespace sv_207b50d62092455aaaf6793d4cb5d22e.Models;

// Service contract records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

@* Horizontal step progress indicator with clickable completed steps *@

<nav aria-label="Application progress">
    <ol class="step-indicator">
        @for (var i = 0; i < _stepLabels.Length; i++)
        {
            var step = i + 1;
            var css = step == CurrentStep ? "step active"
                    : CompletedSteps.Contains(step) ? "step completed"
                    : "step";

            <li class="@css" @onclick="() => SelectStep(step)" role="button" aria-current="@(step == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(step) && step != CurrentStep)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <span class="step-label">@_stepLabels[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; } = 1;
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private static readonly string[] _stepLabels =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task SelectStep(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    justify-content: space-between;
    margin-bottom: 2rem;
    padding: 0;
    list-style: none;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    cursor: default;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
    z-index: 1;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: white;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    color: #6c757d;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

/* Connector line between steps */
.step:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed:not(:last-child)::after {
    background: #198754;
}

@using sv_207b50d62092455aaaf6793d4cb5d22e.Models
@inject IApplicationService ApplicationService

<div>
    <h4>Personal Information</h4>
    <hr />

    @if (_errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in _errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.FullName" placeholder="John Doe" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="Model.Email" placeholder="john@example.com" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" placeholder="(555) 123-4567" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.Address" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
            @if (_validating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private List<string> _errors = new();
    private bool _validating;

    private async Task HandleNext()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName)) _errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email)) _errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone)) _errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address)) _errors.Add("Address is required.");

        if (_errors.Count > 0) return;

        _validating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                _errors.Add("The email address could not be verified. Please check and try again.");
                return;
            }
        }
        finally
        {
            _validating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_207b50d62092455aaaf6793d4cb5d22e.Models

<div>
    <h4>Work History</h4>
    <hr />

    @if (_errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in _errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (var i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (var i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                _errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                _errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate is null)
                _errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (_errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

@using sv_207b50d62092455aaaf6793d4cb5d22e.Models

<div>
    <h4>References</h4>
    <hr />

    @if (_errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in _errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (var i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (var i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                _errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                _errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                _errors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                _errors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (_errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

@using sv_207b50d62092455aaaf6793d4cb5d22e.Models

<div>
    <h4>Review Your Application</h4>
    <hr />

    @if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }

    <!-- Personal Information -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="" @onclick="() => EditSection(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@PersonalInfo.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@PersonalInfo.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@PersonalInfo.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@PersonalInfo.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="" @onclick="() => EditSection(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <h6 class="mb-1">@entry.Title <span class="text-muted fw-normal">at</span> @entry.Company</h6>
                    <p class="text-muted mb-1">
                        @(entry.StartDate?.ToString("MMM yyyy") ?? "—")
                        &ndash;
                        @(entry.IsCurrent ? "Present" : (entry.EndDate?.ToString("MMM yyyy") ?? "—"))
                    </p>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="" @onclick="() => EditSection(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-muted">@r.Email &middot; @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="" @onclick="() => EditSection(4)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(none)" : CoverLetter)</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
            @if (_submitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel PersonalInfo { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _error;

    private async Task EditSection(int step)
    {
        await OnEditSection.InvokeAsync(step);
    }

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

@page "/apply"
@rendermode InteractiveServer
@using sv_207b50d62092455aaaf6793d4cb5d22e.Models
@using sv_207b50d62092455aaaf6793d4cb5d22e.Components.JobApplication
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (_submitted)
    {
        <div class="text-center py-5">
            <div class="mb-4">
                <span style="font-size: 4rem; color: #198754;">&#10003;</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p>Your application ID is <strong>#@_applicationId</strong></p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepSelected="GoToStep" />

        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_personalInfo"
                                  OnNext="() => CompleteAndAdvance(1)" />
                break;
            case 2:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="() => CompleteAndAdvance(2)"
                                 OnBack="() => GoToStep(1)" />
                break;
            case 3:
                <ReferencesStep References="_references"
                                OnNext="() => CompleteAndAdvance(3)"
                                OnBack="() => GoToStep(2)" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnNext="() => CompleteAndAdvance(4)"
                                 OnBack="() => GoToStep(3)" />
                break;
            case 5:
                <ReviewStep PersonalInfo="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="@_coverLetter"
                            OnEditSection="GoToStep"
                            OnBack="() => GoToStep(4)"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = new();
    private bool _submitted;
    private int _applicationId;

    // Shared form state
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = new() { new() };
    private readonly List<ReferenceModel> _references = new() { new(), new() };
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        if (step == _currentStep) return;

        // Allow navigating to completed steps or the next uncompleted step
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _currentStep = step;
        }
    }

    private void CompleteAndAdvance(int completedStep)
    {
