.step.completed .step-label {
    color: #198754;
}

/* Connector line between steps */
.step:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed:not(:last-child)::after {
    background: #198754;
}
"}

