toolArgs.file_text:
.step-indicator {
    display: flex;
    justify-content: space-between;
    margin-bottom: 2rem;
    padding: 0;
    list-style: none;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    cursor: default;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
    z-index: 1;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: white;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    color: #6c757d;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

/* Connector line between steps */
.step:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed:not(:last-child)::after {
    background: #198754;
}

