toolArgs.file_text:
@using sv_207b50d62092455aaaf6793d4cb5d22e.Models

<div>
    <h4>Work History</h4>
    <hr />

    @if (_errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in _errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (var i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (var i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                _errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                _errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate is null)
                _errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (_errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

